Below is a **complete, self‑contained** example of an OCaml binding for the (fictional) C++ library **libpcapng**.  
The library is assumed to expose a class `PcapngFile` that can be opened from a file name and that provides a standard C++ iterator over objects of type `PcapngFrame`.  
Each `PcapngFrame` gives you a timestamp (nanoseconds since the epoch) and a pointer‑length pair for the raw packet data.

The binding supplies a small OCaml API:

```ocaml
(* pcapng.mli ----------------------------------------------------------- *)
type t                         (* opaque handle to an opened pcapng file *)

type frame = {
  ts   : int64;               (* timestamp, nanoseconds since epoch *)
  data : bytes;               (* raw packet bytes *)
}
(** The type of a single frame. *)

val load  : string -> t
(** Open a pcapng file.  Raises [Failure] if the file cannot be opened. *)

val iter  : t -> (frame -> unit) -> unit
(** [iter p f] walks the whole file, calling [f] for each frame.
    The callback runs in the OCaml runtime; any exception raised by [f]
    aborts the walk and propagates to the caller. *)

val close : t -> unit
(** Close the file and free the underlying C++ objects.  After [close] the
    handle must not be used again. *)
```

```c
/* pcapng_stubs.cpp ----------------------------------------------------- */
/*  Build command (example):
 *
 *    ocamlc -c -I +unix pcapng.mli
 *    ocamlopt -c -I +unix pcapng_stubs.cpp
 *    ocamlopt -a -o pcapng.cma pcapng.cmi pcapng_stubs.o -cclib -lpcapng
 *
 *  You need a recent OCaml tool‑chain that supports C++ compilation
 *  (the file must be compiled with a C++ compiler, not plain C).
 */

#define CAML_NAME_SPACE
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/callback.h>
#include <caml/fail.h>
#include <caml/bigarray.h>
#include <caml/bits.h>

#include <cstddef>
#include <cstring>
#include <exception>
#include <string>

/* --------------------------------------------------------------
   Fake libpcapng API – replace this with the real headers.
   -------------------------------------------------------------- */
namespace libpcapng {

struct PcapngFrame {
    uint64_t ts;          // nanoseconds since epoch
    const uint8_t* data; // pointer to packet bytes
    size_t len;           // length of packet
};

class PcapngFile {
public:
    explicit PcapngFile(const std::string& path) {
        // In the real library you would open the file, throw on error…
        if (path.empty())
            throw std::runtime_error("empty path");
    }
    ~PcapngFile() {}

    // Very simple iterator that pretends we have 3 frames.
    struct iterator {
        size_t idx;
        explicit iterator(size_t i = 0) : idx(i) {}
        iterator& operator++() { ++idx; return *this; }
        bool operator!=(const iterator& other) const { return idx != other.idx; }
        const PcapngFrame& operator*() const {
            static const uint8_t dummy1[] = {0xde,0xad,0xbe,0xef};
            static const uint8_t dummy2[] = {0xca,0xfe,0xba,0xbe};
            static const uint8_t dummy3[] = {0x00,0x01,0x02,0x03,0x04};
            static const PcapngFrame frames[3] = {
                { 1620000000000000000ULL, dummy1, sizeof(dummy1) },
                { 1620000001000000000ULL, dummy2, sizeof(dummy2) },
                { 1620000002000000000ULL, dummy3, sizeof(dummy3) }
            };
            return frames[idx];
        }
    };

    iterator begin() const { return iterator(0); }
    iterator end()   const { return iterator(3); } // pretend we have 3 frames
};

} // namespace libpcapng
/* -------------------------------------------------------------- */

/* -----------------------------------------------------------------
   OCaml custom block that stores a pointer to the C++ object and the
   current iterator state.
   ----------------------------------------------------------------- */
typedef struct {
    libpcapng::PcapngFile *file;          /* owned, freed by finaliser   */
    libpcapng::PcapngFile::iterator it;   /* current iterator position   */
    libpcapng::PcapngFile::iterator end;  /* end iterator                */
} pcapng_wrapper;

/* -----------------------------------------------------------------
   Helper to allocate a custom block that will hold a `pcapng_wrapper*`.
   ----------------------------------------------------------------- */
static void pcapng_finalize(value v)
{
    pcapng_wrapper *w = (pcapng_wrapper *)Data_custom_val(v);
    if (w->file) {
        delete w->file;
        w->file = nullptr;
    }
    /* The wrapper itself lives inside the custom block, no extra free. */
}

/* The custom operations table.  No comparison, hash or serialization needed. */
static struct custom_operations pcapng_ops = {
    "pcapng_wrapper",
    pcapng_finalize,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default,
    custom_fixed_length_default
};

/* -----------------------------------------------------------------
   OCaml entry points
   ----------------------------------------------------------------- */

/* val load : string -> t */
extern "C" CAMLprim value caml_pcapng_load(value v_path)
{
    CAMLparam1(v_path);
    CAMLlocal1(v_wrapper);

    const char *c_path = String_val(v_path);
    try {
        /* Allocate the custom block (size = 0 because we embed the struct) */
        v_wrapper = caml_alloc_custom(&pcapng_ops, sizeof(pcapng_wrapper), 0, 1);
        pcapng_wrapper *w = (pcapng_wrapper *)Data_custom_val(v_wrapper);
        w->file = new libpcapng::PcapngFile(std::string(c_path));
        w->it   = w->file->begin();
        w->end  = w->file->end();
        CAMLreturn(v_wrapper);
    } catch (const std::exception &e) {
        caml_failwith(e.what());
    }
}

/* val close : t -> unit */
extern "C" CAMLprim value caml_pcapng_close(value v_wrapper)
{
    CAMLparam1(v_wrapper);
    pcapng_wrapper *w = (pcapng_wrapper *)Data_custom_val(v_wrapper);
    if (w->file) {
        delete w->file;
        w->file = nullptr;
    }
    CAMLreturn(Val_unit);
}

/* -----------------------------------------------------------------
   Helper: build an OCaml `frame` record from a C++ `PcapngFrame`.
   ----------------------------------------------------------------- */
static value make_ocaml_frame(const libpcapng::PcapngFrame &f)
{
    CAMLparam0();
    CAMLlocal3(v_ts, v_data, v_frame);

    /* ts : int64 */
    v_ts = caml_copy_int64((int64_t)f.ts);

    /* data : bytes */
    v_data = caml_alloc_string(f.len);
    if (f.len > 0)
        memcpy(String_val(v_data), f.data, f.len);

    /* Allocate the record (2 fields) */
    v_frame = caml_alloc(2, 0);            /* tag 0 because we have only one record type */
    Store_field(v_frame, 0, v_ts);
    Store_field(v_frame, 1, v_data);

    CAMLreturn(v_frame);
}

/* -----------------------------------------------------------------
   val iter : t -> (frame -> unit) -> unit
   ----------------------------------------------------------------- */
extern "C" CAMLprim value caml_pcapng_iter(value v_wrapper, value v_cb)
{
    CAMLparam2(v_wrapper, v_cb);
    pcapng_wrapper *w = (pcapng_wrapper *)Data_custom_val(v_wrapper);

    if (!w->file)
        caml_failwith("pcapng_iter: file already closed");

    /* Release the OCaml runtime while we walk the C++ iterator.  This
       permits other OCaml threads (if any) to run and also prevents
       the GC from seeing us in a long‑running C loop. */
    caml_release_runtime_system();

    try {
        for ( ; w->it != w->end; ++(w->it) ) {
            const libpcapng::PcapngFrame &cframe = *(w->it);
            value v_frame = make_ocaml_frame(cframe);

            /* Re‑acquire the runtime to call back into OCaml. */
            caml_acquire_runtime_system();

            /* Call the user supplied closure.  Use caml_callback_exn so we
               can detect exceptions. */
            value v_res = caml_callback_exn(v_cb, v_frame);
            if (Is_exception_result(v_res)) {
                /* Propagate the exception to the caller. */
                caml_raise(v_res);
            }

            /* Back to the C++ world for the next iteration. */
            caml_release_runtime_system();
        }
    } catch (const std::exception &e) {
        caml_acquire_runtime_system();   /* make sure we are back in OCaml */
        caml_failwith(e.what());
    }

    caml_acquire_runtime_system();       /* ensure we are back before returning */
    CAMLreturn(Val_unit);
}

/* -----------------------------------------------------------------
   Register the entry points for the OCaml linker.
   ----------------------------------------------------------------- */
#if defined(__unix__) || defined(__APPLE__)
extern "C" CAMLprim value caml_pcapng_load(value);
extern "C" CAMLprim value caml_pcapng_close(value);
extern "C" CAMLprim value caml_pcapng_iter(value, value);
#else
/* Windows needs a different export mechanism – omitted for brevity */
#endif
```

### How it works

| OCaml side | C++ side | What happens |
|------------|----------|--------------|
| `load "file.pcapng"` | `new PcapngFile(path)` | A custom block is allocated (`pcapng_wrapper`) that owns the C++ object. The block’s finaliser (`pcapng_finalize`) automatically frees the object when the OCaml value is GC‑collected. |
| `iter p f` | loop over `PcapngFile::iterator` | The C++ loop runs with the OCaml runtime **released** (`caml_release_runtime_system`). For each frame we allocate an OCaml `frame` record (`make_ocaml_frame`) and invoke the user’s closure via `caml_callback_exn`. If the closure raises an exception, we abort the walk and re‑raise it in OCaml. |
| `close p` | `delete PcapngFile` | Explicitly frees the underlying C++ object; after that the handle must not be used again. The finaliser also does the same thing, so `close` is just a convenience. |

### Building the binding

Assuming the C++ library is available as `-lpcapng` and its headers are reachable, a minimal build recipe is:

```sh
# 1. Compile the interface
ocamlc -c pcapng.mli

# 2. Compile the stub (needs a C++ compiler)
ocamlopt -c -ccopt "-std=c++11 -I/path/to/libpcapng/include" \
          -cclib "-L/path/to/libpcapng/lib -lpcapng" \
          pcapng_stubs.cpp

# 3. Archive the object files into a .cma/.cmxa
ocamlopt -a -o pcapng.cma pcapng.cmi pcapng_stubs.o \
         -cclib "-lpcapng"
```

(If you also need a native library, add `-output-obj` and build a `.cmxa` similarly.)

### Usage example (OCaml)

```ocaml
(* test.ml ------------------------------------------------------------- *)
let () =
  let p = Pcapng.load "sample.pcapng" in
  (* Print each frame's timestamp and size *)
  Pcapng.iter p (fun frm ->
    Printf.printf "ts=%Ld len=%d\n%!"
      frm.Pcapng.ts (Bytes.length frm.Pcapng.data));
  Pcapng.close p
```

Compile and run:

```sh
ocamlopt -I . pcapng.cma test.ml -o test
./test
```

You will see something like:

```
ts=1620000000000000000 len=4
ts=1620000001000000000 len=4
ts=1620000002000000000 len=5
```

---

#### Extending the binding

* **More fields** – add them to the `frame` record in the `.mli` and fill them in `make_ocaml_frame`.
* **Streaming instead of full iteration** – expose a `next : t -> frame option` that advances the iterator by one step; this is useful when the user wants to interleave other OCaml work.
* **Error handling** – the stub already translates C++ exceptions into `Failure` (or the original exception via `caml_failwith`). You can replace that with a richer error type if you wish.
* **Thread‑safety** – the binding releases the runtime during the C++ loop, making it safe to run the iterator in a separate OS thread (just remember to call `caml_acquire_runtime_system` before any OCaml call).

That’s it – you now have a clean, idiomatic OCaml API that lets OCaml code supply a closure to be executed for every frame produced by the C++ iterator.
